"""Comprehensive tests for the token bucket rate limiter with decorator support."""

from __future__ import annotations

import asyncio
import threading
import time

import pytest

from src.token_bucket import (
    RateLimitExceeded,
    TokenBucket,
    rate_limit,
    rate_limit_method,
)


# ---------------------------------------------------------------------------
# Core TokenBucket tests
# ---------------------------------------------------------------------------


class TestTokenBucket:
    """Tests for the core TokenBucket class."""

    def test_initial_tokens_equals_capacity(self) -> None:
        bucket = TokenBucket(10, 1)
        assert bucket.tokens == pytest.approx(10, abs=0.1)

    def test_consume_reduces_tokens(self) -> None:
        bucket = TokenBucket(10, 1)
        assert bucket.consume(3) is True
        assert bucket.tokens == pytest.approx(7, abs=0.5)

    def test_consume_default_one_token(self) -> None:
        bucket = TokenBucket(5, 1)
        assert bucket.consume() is True
        assert bucket.tokens < 5

    def test_consume_returns_false_when_exhausted(self) -> None:
        bucket = TokenBucket(2, 1)
        assert bucket.consume(2) is True
        assert bucket.consume(1) is False

    def test_consume_exact_capacity(self) -> None:
        bucket = TokenBucket(5, 1)
        assert bucket.consume(5) is True
        assert bucket.tokens == pytest.approx(0, abs=0.1)

    def test_consume_zero_tokens_always_succeeds(self) -> None:
        bucket = TokenBucket(0.5, 1)
        bucket.consume(0.5)
        assert bucket.consume(0) is True

    def test_consume_negative_raises(self) -> None:
        bucket = TokenBucket(5, 1)
        with pytest.raises(ValueError):
            bucket.consume(-1)

    def test_refill_over_time(self) -> None:
        bucket = TokenBucket(10, 100)  # 100 tokens/sec => refills fast
        bucket.consume(10)
        assert bucket.tokens == pytest.approx(0, abs=0.5)
        time.sleep(0.05)  # ~5 tokens should refill
        tokens = bucket.tokens
        assert tokens > 0

    def test_refill_capped_at_capacity(self) -> None:
        bucket = TokenBucket(5, 1000)  # extremely fast refill
        bucket.consume(1)
        time.sleep(0.05)
        assert bucket.tokens <= 5.0

    def test_capacity_property(self) -> None:
        bucket = TokenBucket(42, 7)
        assert bucket.capacity == 42

    def test_refill_rate_property(self) -> None:
        bucket = TokenBucket(42, 7)
        assert bucket.refill_rate == 7

    def test_invalid_capacity_raises(self) -> None:
        with pytest.raises(ValueError):
            TokenBucket(0, 1)
        with pytest.raises(ValueError):
            TokenBucket(-5, 1)

    def test_invalid_refill_rate_raises(self) -> None:
        with pytest.raises(ValueError):
            TokenBucket(5, 0)
        with pytest.raises(ValueError):
            TokenBucket(5, -1)

    def test_wait_time_when_tokens_available(self) -> None:
        bucket = TokenBucket(10, 1)
        assert bucket.wait_time(5) == 0.0

    def test_wait_time_when_tokens_deficit(self) -> None:
        bucket = TokenBucket(5, 10)
        bucket.consume(5)
        # Need 3 tokens, refill is 10/s => ~0.3s
        wt = bucket.wait_time(3)
        assert 0.1 < wt < 0.5

    def test_concurrent_consumption(self) -> None:
        """Multiple threads consuming from the same bucket should be safe."""
        bucket = TokenBucket(100, 0)  # no refill — fixed pool of 100
        # We intentionally set refill_rate to something valid but tiny.
        bucket = TokenBucket(100, 0.001)
        successes: list[bool] = []
        lock = threading.Lock()

        def consume_one() -> None:
            result = bucket.consume(1)
            with lock:
                successes.append(result)

        threads = [threading.Thread(target=consume_one) for _ in range(150)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        assert len(successes) == 150
        assert sum(successes) == 100  # exactly 100 should succeed
        assert successes.count(False) == 50

    def test_fractional_tokens(self) -> None:
        bucket = TokenBucket(1.5, 1)
        assert bucket.consume(0.75) is True
        assert bucket.consume(0.75) is True
        assert bucket.consume(0.01) is False


# ---------------------------------------------------------------------------
# rate_limit decorator tests (non-blocking)
# ---------------------------------------------------------------------------


class TestRateLimitNonBlocking:
    """Tests for the @rate_limit decorator in non-blocking mode."""

    def test_basic_call_succeeds(self) -> None:
        @rate_limit(capacity=5, refill_rate=1)
        def greet(name: str) -> str:
            return f"hello {name}"

        assert greet("world") == "hello world"

    def test_calls_succeed_until_exhausted(self) -> None:
        @rate_limit(capacity=3, refill_rate=0.001)
        def action() -> str:
            return "ok"

        assert action() == "ok"
        assert action() == "ok"
        assert action() == "ok"
        with pytest.raises(RateLimitExceeded):
            action()

    def test_raises_rate_limit_exceeded(self) -> None:
        @rate_limit(capacity=1, refill_rate=0.001)
        def action() -> None:
            pass

        action()
        with pytest.raises(RateLimitExceeded) as exc_info:
            action()
        assert exc_info.value.retry_after > 0

    def test_tokens_per_call(self) -> None:
        @rate_limit(capacity=10, refill_rate=0.001, tokens_per_call=5)
        def heavy() -> str:
            return "done"

        assert heavy() == "done"  # consumes 5
        assert heavy() == "done"  # consumes 5 (total 10)
        with pytest.raises(RateLimitExceeded):
            heavy()  # no tokens left

    def test_preserves_function_metadata(self) -> None:
        @rate_limit(capacity=5, refill_rate=1)
        def my_func() -> None:
            """My docstring."""
            pass

        assert my_func.__name__ == "my_func"
        assert my_func.__doc__ == "My docstring."

    def test_bucket_exposed(self) -> None:
        @rate_limit(capacity=5, refill_rate=1)
        def action() -> None:
            pass

        assert isinstance(action.bucket, TokenBucket)

    def test_return_value_preserved(self) -> None:
        @rate_limit(capacity=5, refill_rate=1)
        def add(a: int, b: int) -> int:
            return a + b

        assert add(2, 3) == 5

    def test_exception_in_function_propagates(self) -> None:
        @rate_limit(capacity=5, refill_rate=1)
        def fail() -> None:
            raise ValueError("boom")

        with pytest.raises(ValueError, match="boom"):
            fail()


# ---------------------------------------------------------------------------
# rate_limit decorator tests (blocking)
# ---------------------------------------------------------------------------


class TestRateLimitBlocking:
    """Tests for the @rate_limit decorator with block=True."""

    def test_blocking_waits_for_token(self) -> None:
        @rate_limit(capacity=1, refill_rate=100, block=True)
        def action() -> str:
            return "ok"

        # First call consumes the token.
        assert action() == "ok"
        # Second call should block briefly until refill, then succeed.
        start = time.monotonic()
        assert action() == "ok"
        elapsed = time.monotonic() - start
        # Should have waited some small amount of time.
        assert elapsed < 1.0  # but definitely finishes

    def test_blocking_with_timeout_succeeds(self) -> None:
        @rate_limit(capacity=1, refill_rate=100, block=True, timeout=2.0)
        def action() -> str:
            return "ok"

        action()  # consume
        assert action() == "ok"  # should refill within timeout

    def test_blocking_timeout_exceeded(self) -> None:
        @rate_limit(capacity=1, refill_rate=0.1, block=True, timeout=0.05)
        def action() -> str:
            return "ok"

        action()  # consume the single token
        with pytest.raises(RateLimitExceeded):
            action()  # refill far too slow for the 0.05s timeout


# ---------------------------------------------------------------------------
# rate_limit_method tests
# ---------------------------------------------------------------------------


class TestRateLimitMethod:
    """Tests for @rate_limit_method — per-instance buckets."""

    def test_different_instances_have_separate_buckets(self) -> None:
        class Api:
            @rate_limit_method(capacity=2, refill_rate=0.001)
            def call(self) -> str:
                return "ok"

        a = Api()
        b = Api()

        # Each instance gets 2 tokens.
        assert a.call() == "ok"
        assert a.call() == "ok"
        with pytest.raises(RateLimitExceeded):
            a.call()

        # b is independent — still has its tokens.
        assert b.call() == "ok"
        assert b.call() == "ok"
        with pytest.raises(RateLimitExceeded):
            b.call()

    def test_same_instance_shares_bucket(self) -> None:
        class Api:
            @rate_limit_method(capacity=3, refill_rate=0.001)
            def call(self) -> str:
                return "ok"

        a = Api()
        a.call()
        a.call()
        a.call()
        with pytest.raises(RateLimitExceeded):
            a.call()

    def test_bucket_cleanup_on_instance_deletion(self) -> None:
        class Api:
            @rate_limit_method(capacity=5, refill_rate=1)
            def call(self) -> str:
                return "ok"

        a = Api()
        a.call()

        # Access the internal buckets dict to verify cleanup.
        buckets = Api.call._buckets
        key = id(a)
        assert key in buckets

        del a
        # After deletion, the weakref finalizer should have removed the entry.
        assert key not in buckets

    def test_blocking_per_instance(self) -> None:
        class Api:
            @rate_limit_method(capacity=1, refill_rate=100, block=True)
            def call(self) -> str:
                return "ok"

        a = Api()
        assert a.call() == "ok"
        assert a.call() == "ok"  # blocks briefly, then succeeds


# ---------------------------------------------------------------------------
# RateLimitExceeded exception tests
# ---------------------------------------------------------------------------


class TestRateLimitExceededException:
    """Tests for the RateLimitExceeded exception."""

    def test_has_retry_after(self) -> None:
        exc = RateLimitExceeded(retry_after=1.5)
        assert exc.retry_after == 1.5

    def test_retry_after_from_decorator(self) -> None:
        @rate_limit(capacity=1, refill_rate=10)
        def action() -> None:
            pass

        action()
        with pytest.raises(RateLimitExceeded) as exc_info:
            action()
        assert isinstance(exc_info.value.retry_after, float)
        assert exc_info.value.retry_after > 0

    def test_is_exception(self) -> None:
        assert issubclass(RateLimitExceeded, Exception)

    def test_message(self) -> None:
        exc = RateLimitExceeded(retry_after=2.0, message="slow down")
        assert str(exc) == "slow down"

    def test_default_message(self) -> None:
        exc = RateLimitExceeded(retry_after=0.5)
        assert "0.500" in str(exc)


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------


class TestEdgeCases:
    """Edge case tests."""

    def test_decorating_async_function_raises_type_error(self) -> None:
