            @rate_limit(capacity=5, refill_rate=1)
            async def coro() -> None:
                pass

    def test_decorating_async_method_raises_type_error(self) -> None:
        with pytest.raises(TypeError, match="async"):

            class Api:
                @rate_limit_method(capacity=5, refill_rate=1)
                async def call(self) -> None:
                    pass

    def test_zero_token_consumption(self) -> None:
        bucket = TokenBucket(1, 1)
        assert bucket.consume(0) is True
        # All tokens remain.
        assert bucket.tokens == pytest.approx(1.0, abs=0.1)

    def test_large_burst_then_refill(self) -> None:
        bucket = TokenBucket(100, 1000)
        for _ in range(100):
            assert bucket.consume(1) is True
        assert bucket.consume(1) is False
        time.sleep(0.05)  # ~50 tokens refill
        assert bucket.tokens > 10

    def test_concurrent_decorator_calls(self) -> None:
        @rate_limit(capacity=50, refill_rate=0.001)
        def action() -> bool:
            return True

        results: list[Any] = []
        lock = threading.Lock()

        def call_action() -> None:
            try:
                result = action()
            except RateLimitExceeded:
                result = None
            with lock:
                results.append(result)

        threads = [threading.Thread(target=call_action) for _ in range(100)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        assert len(results) == 100
        successes = [r for r in results if r is True]
        failures = [r for r in results if r is None]
        assert len(successes) == 50
        assert len(failures) == 50

