"""Comprehensive tests for the token bucket rate limiter.

Covers: core bucket mechanics, blocking acquire, decorator patterns,
per-instance method limiting, thread safety, and edge cases.
"""

from __future__ import annotations

import threading
import time

import pytest

from src.token_bucket import (
    RateLimitExceeded,
    TokenBucket,
    rate_limit,
    rate_limit_method,
)


# ---------------------------------------------------------------------------
# Core TokenBucket — construction & validation
# ---------------------------------------------------------------------------


class TestConstruction:
    def test_initial_tokens_equal_capacity(self) -> None:
        bucket = TokenBucket(10, 1)
        assert bucket.tokens == pytest.approx(10, abs=0.1)

    def test_properties(self) -> None:
        bucket = TokenBucket(42, 3.14)
        assert bucket.capacity == 42
        assert bucket.refill_rate == pytest.approx(3.14)

    def test_zero_capacity_raises(self) -> None:
        with pytest.raises(ValueError, match="capacity must be positive"):
            TokenBucket(0, 1)

    def test_negative_capacity_raises(self) -> None:
        with pytest.raises(ValueError, match="capacity must be positive"):
            TokenBucket(-5, 1)

    def test_zero_refill_rate_raises(self) -> None:
        with pytest.raises(ValueError, match="refill_rate must be positive"):
            TokenBucket(10, 0)

    def test_negative_refill_rate_raises(self) -> None:
        with pytest.raises(ValueError, match="refill_rate must be positive"):
            TokenBucket(10, -1)

    def test_repr(self) -> None:
        bucket = TokenBucket(5, 1)
        r = repr(bucket)
        assert "capacity=5" in r
        assert "refill_rate=1" in r
        assert "tokens=" in r


# ---------------------------------------------------------------------------
# Core TokenBucket — consume()
# ---------------------------------------------------------------------------


class TestConsume:
    def test_consume_single_token(self) -> None:
        bucket = TokenBucket(10, 0.001)
        assert bucket.consume() is True
        assert bucket.tokens == pytest.approx(9, abs=0.1)

    def test_consume_multiple_tokens(self) -> None:
        bucket = TokenBucket(10, 0.001)
        assert bucket.consume(5) is True
        assert bucket.tokens == pytest.approx(5, abs=0.1)

    def test_consume_exact_capacity(self) -> None:
        bucket = TokenBucket(5, 0.001)
        assert bucket.consume(5) is True
        assert bucket.tokens == pytest.approx(0, abs=0.1)

    def test_returns_false_when_exhausted(self) -> None:
        bucket = TokenBucket(2, 0.001)
        assert bucket.consume(2) is True
        assert bucket.consume(1) is False

    def test_all_or_nothing(self) -> None:
        """Failing consume doesn't take partial tokens."""
        bucket = TokenBucket(3, 0.001)
        bucket.consume(2)
        assert bucket.consume(2) is False
        assert bucket.tokens == pytest.approx(1, abs=0.1)

    def test_consume_zero_always_succeeds(self) -> None:
        bucket = TokenBucket(1, 0.001)
        bucket.consume(1)
        assert bucket.consume(0) is True

    def test_consume_exceeding_capacity_returns_false(self) -> None:
        bucket = TokenBucket(5, 1)
        assert bucket.consume(6) is False
        assert bucket.tokens == pytest.approx(5, abs=0.1)

    def test_consume_negative_raises(self) -> None:
        bucket = TokenBucket(5, 1)
        with pytest.raises(ValueError, match="non-negative"):
            bucket.consume(-1)

    def test_fractional_tokens(self) -> None:
        bucket = TokenBucket(1.5, 0.001)
        assert bucket.consume(0.5) is True
        assert bucket.consume(0.75) is True
        assert bucket.tokens == pytest.approx(0.25, abs=0.01)
        assert bucket.consume(0.3) is False


# ---------------------------------------------------------------------------
# Core TokenBucket — refill
# ---------------------------------------------------------------------------


class TestRefill:
    def test_tokens_refill_after_waiting(self) -> None:
        bucket = TokenBucket(10, 100)  # 100 tok/s
        bucket.consume(10)
        assert bucket.tokens == pytest.approx(0, abs=0.5)
        time.sleep(0.05)  # ~5 tokens
        assert bucket.tokens >= 3

    def test_never_exceeds_capacity(self) -> None:
        bucket = TokenBucket(5, 1000)
        time.sleep(0.05)
        assert bucket.tokens <= 5.0

    def test_never_exceeds_capacity_after_long_wait(self) -> None:
        bucket = TokenBucket(10, 10)
        time.sleep(0.1)
        assert bucket.tokens == pytest.approx(10.0)

    def test_partial_refill(self) -> None:
        bucket = TokenBucket(10, 20)  # 20 tok/s
        bucket.consume(10)
        time.sleep(0.1)  # ~2 tokens
        assert 1.0 <= bucket.tokens <= 4.0


# ---------------------------------------------------------------------------
# Core TokenBucket — wait_time()
# ---------------------------------------------------------------------------


class TestWaitTime:
    def test_zero_when_available(self) -> None:
        bucket = TokenBucket(10, 1)
        assert bucket.wait_time(5) == 0.0

    def test_correct_estimate(self) -> None:
        bucket = TokenBucket(10, 2)  # 2 tok/s
        bucket.consume(10)
        wt = bucket.wait_time(4)
        assert 1.5 <= wt <= 2.5

    def test_exceeds_capacity_returns_inf(self) -> None:
        bucket = TokenBucket(5, 1)
        assert bucket.wait_time(6) == float("inf")

    def test_zero_tokens_returns_zero(self) -> None:
        bucket = TokenBucket(5, 1)
        assert bucket.wait_time(0) == 0.0

    def test_negative_raises(self) -> None:
        bucket = TokenBucket(5, 1)
        with pytest.raises(ValueError):
            bucket.wait_time(-1)


# ---------------------------------------------------------------------------
# Core TokenBucket — acquire() context manager
# ---------------------------------------------------------------------------


class TestAcquire:
    def test_immediate_when_available(self) -> None:
        bucket = TokenBucket(10, 1)
        with bucket.acquire(5):
            pass
        assert bucket.tokens == pytest.approx(5, abs=0.1)

    def test_blocks_until_refill(self) -> None:
        bucket = TokenBucket(5, 100)
        bucket.consume(5)
        start = time.monotonic()
        with bucket.acquire(3, timeout=2.0):
            elapsed = time.monotonic() - start
        assert elapsed >= 0.01
        assert elapsed < 1.0

    def test_raises_timeout_error(self) -> None:
        bucket = TokenBucket(10, 1)
        bucket.consume(10)
        with pytest.raises(TimeoutError):
            with bucket.acquire(10, timeout=0.05):
                pass

    def test_zero_tokens(self) -> None:
        bucket = TokenBucket(5, 1)
        bucket.consume(5)
        with bucket.acquire(0):
            pass  # immediate, even when empty

    def test_exceeding_capacity_raises(self) -> None:
        bucket = TokenBucket(5, 1)
        with pytest.raises(ValueError):
            with bucket.acquire(6):
                pass

    def test_negative_raises(self) -> None:
        bucket = TokenBucket(5, 1)
        with pytest.raises(ValueError):
            with bucket.acquire(-1):
                pass

    def test_no_timeout_blocks_indefinitely(self) -> None:
        bucket = TokenBucket(5, 200)
        bucket.consume(5)
