"""Comprehensive tests for the token bucket rate limiter.

Covers: core bucket mechanics, blocking acquire, decorator patterns,
per-instance method limiting, thread safety, and edge cases.
"""

from __future__ import annotations

import threading
import time

import pytest

from src.token_bucket import (
    RateLimitExceeded,
    TokenBucket,
    rate_limit,
    rate_limit_method,
)


