    def test_rapid_consume_refill_cycle(self) -> None:
        bucket = TokenBucket(1, 1000)
        for _ in range(50):
            bucket.consume(1)
            time.sleep(0.002)
        assert 0 <= bucket.tokens <= 1.0

    def test_async_function_rejected_by_rate_limit(self) -> None:
        with pytest.raises(TypeError, match="async"):
            @rate_limit(capacity=5, refill_rate=1)
            async def coro() -> None:
                pass

    def test_async_method_rejected_by_rate_limit_method(self) -> None:
        with pytest.raises(TypeError, match="async"):
            class Api:
                @rate_limit_method(capacity=5, refill_rate=1)
                async def call(self) -> None:
                    pass

    def test_concurrent_decorator_calls(self) -> None:
        @rate_limit(capacity=50, refill_rate=0.001)
        def action() -> bool:
            return True

        results: list[object] = []
        lock = threading.Lock()

        def call_action() -> None:
            try:
                result = action()
            except RateLimitExceeded:
                result = None
            with lock:
                results.append(result)

        threads = [threading.Thread(target=call_action) for _ in range(100)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()

        assert len(results) == 100
        assert sum(1 for r in results if r is True) == 50
        assert sum(1 for r in results if r is None) == 50
